def login_required(f):
    """Decorator to require authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


def generate_saml_request():
    """Generate a SAML AuthnRequest."""
    request_id = f'_{"".join(secrets.token_hex(16))}'
    issue_instant = datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')

    authn_request = f'''<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{SAML_CONFIG['idp_sso_url']}"
    AssertionConsumerServiceURL="{SAML_CONFIG['sp_acs_url']}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{SAML_CONFIG['sp_entity_id']}</saml:Issuer>
    <samlp:NameIDPolicy
        Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
        AllowCreate="true"/>
</samlp:AuthnRequest>'''

    # Store request ID for InResponseTo validation
    session['saml_request_id'] = request_id
    session['saml_request_time'] = datetime.now(timezone.utc).isoformat()

    return authn_request, request_id


@app.route('/')
def index():
    """Home page."""
    if 'user' in session:
        return jsonify({
            'message': 'Authenticated',
            'user': session['user'],
        })
    return jsonify({
        'message': 'Not authenticated',
        'login_url': url_for('login'),
    })


@app.route('/login')
def login():
    """Initiate SAML login by redirecting to IdP."""
    authn_request, request_id = generate_saml_request()

    # Base64 encode the request
    encoded_request = base64.b64encode(authn_request.encode('utf-8')).decode('utf-8')

    # Generate a relay state token to prevent CSRF
    relay_state = secrets.token_urlsafe(32)
    session['saml_relay_state'] = relay_state

    # In production, you would redirect to the IdP with the encoded request
    # For HTTP-POST binding:
    return f'''
    <html>
    <body onload="document.forms[0].submit()">
        <form method="POST" action="{SAML_CONFIG['idp_sso_url']}">
            <input type="hidden" name="SAMLRequest" value="{encoded_request}" />
            <input type="hidden" name="RelayState" value="{relay_state}" />
            <noscript>
                <input type="submit" value="Continue to Login" />
            </noscript>
        </form>
    </body>
    </html>
    '''


@app.route('/saml/acs', methods=['POST'])
def assertion_consumer_service():
    """
    Assertion Consumer Service (ACS) endpoint.
    Receives and processes SAML responses from the IdP.
    """
    # Validate content type
    if not request.content_type or 'application/x-www-form-urlencoded' not in request.content_type:
        # Also accept multipart/form-data
        if not request.content_type or 'multipart/form-data' not in request.content_type:
            abort(400, description="Invalid content type")

    saml_response_b64 = request.form.get('SAMLResponse')
    relay_state = request.form.get('RelayState')

    if not saml_response_b64:
        abort(400, description="No SAMLResponse found in request")

    # Validate RelayState to prevent CSRF
    stored_relay_state = session.get('saml_relay_state')
    if stored_relay_state and relay_state:
        if not hmac.compare_digest(stored_relay_state, relay_state):
            abort(403, description="Invalid RelayState (CSRF protection)")

    # Validate the SAML request hasn't expired
    request_time_str = session.get('saml_request_time')
    if request_time_str:
        request_time = datetime.fromisoformat(request_time_str)
        if datetime.now(timezone.utc) - request_time > timedelta(minutes=10):
            abort(400, description="SAML request has expired")

    try:
        # Process the SAML response
        saml_resp = SAMLResponse(saml_response_b64)
        attributes = saml_resp.validate_and_extract()

        # Create user session
        session.permanent = True
        session['user'] = {
            'name_id': saml_resp.name_id,
            'session_index': saml_resp.session_index,
            'attributes': attributes,
            'authenticated_at': datetime.now(timezone.utc).isoformat(),
            'assertion_id': saml_resp.assertion_id,
        }

        # Clean up SAML-specific session data
        session.pop('saml_request_id', None)
        session.pop('saml_request_time', None)
        session.pop('saml_relay_state', None)

        # Log successful authentication (without sensitive data)
        app.logger.info(
            f"SAML authentication successful for NameID: {saml_resp.name_id}, "
            f"AssertionID: {saml_resp.assertion_id}"
        )

        return redirect(url_for('dashboard'))

    except SAMLValidationError as e:
        app.logger.warning(f"SAML validation failed: {e}")
        abort(403, description=f"SAML validation failed: {e}")
    except Exception as e:
        app.logger.error(f"Unexpected error processing SAML response: {e}")
        abort(500, description="Internal error processing authentication response")


@app.route('/dashboard')
@login_required
def dashboard():
    """Protected dashboard page."""
    user = session['user']
    return jsonify({
        'message': 'Welcome to the dashboard',
        'user': {
            'name_id': user.get('name_id'),
            'attributes': user.get('attributes', {}),
            'authenticated_at': user.get('authenticated_at'),
        }
    })


@app.route('/logout')
def logout():
    """Logout and clear session."""
    user = session.get('user', {})
    app.logger.info(f"User logged out: {user.get('name_id', 'unknown')}")
    session.clear()
    return jsonify({'message': 'Logged out successfully'})


@app.route('/saml/metadata')
def metadata():
    """Serve SP metadata."""
    metadata_xml = f'''<?xml version="1.0" encoding="UTF-8"?>
<md:EntityDescriptor
    xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
    entityID="{SAML_CONFIG['sp_entity_id']}">
    <md:SPSSODescriptor
        AuthnRequestsSigned="true"
        WantAssertionsSigned="true"
        protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        <md:AssertionConsumerService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{SAML_CONFIG['sp_acs_url']}"
            index="0"
            isDefault="true"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>'''

    return metadata_xml, 200, {'Content-Type': 'application/xml'}


@app.route('/health')
def health():
    """Health check endpoint."""
    return jsonify({'status': 'healthy', 'timestamp': datetime.now(timezone.utc).isoformat()})


@app.errorhandler(400)
def bad_request(e):
    return jsonify({'error': 'Bad Request', 'message': str(e.description)}), 400


@app.errorhandler(403)
def forbidden(e):
    return jsonify({'error': 'Forbidden', 'message': str(e.description)}), 403


@app.errorhandler(500)
def internal_error(e):
    return jsonify({'error': 'Internal Server Error', 'message': 'An unexpected error occurred'}), 500


if __name__ == '__main__':
    # In production, use a proper WSGI server like gunicorn
    # and ensure HTTPS is configured
    app.run(
        host='0.0.0.0',
        port=int(os.environ.get('PORT', 5000)),
        debug=os.environ.get('FLASK_DEBUG', 'false').lower() == 'true',
    )